        modelBuilder.Entity<WeightSheet>(entity =>
        {
            // PK is clustered on RowUid (per warehouse.WeightSheets DDL —
            // PK_WeightSheets PRIMARY KEY CLUSTERED ([RowUid] ASC)).
            // WeightSheetId is still a bigint column generated by the
            // trg_WeightSheets_AutoGenerateIDs trigger but it is NOT the
            // primary key in this schema.
            entity.HasKey(e => e.RowUid).HasName("PK_WeightSheets");

            entity.ToTable("WeightSheets", "warehouse", tb =>
            {
                tb.HasTrigger("trg_WeightSheets_AutoGenerateIDs");
                tb.HasTrigger("trg_WeightSheets_LockCoreColumns");
            });

            // WeightSheetId is populated by the AutoGenerateIDs INSTEAD OF
            // trigger, so tell EF not to try to read a value back for it.
            entity.Property(e => e.WeightSheetId).ValueGeneratedOnAdd();

            entity.HasIndex(e => e.As400Id, "IX_WeightSheets_As400Id").IsUnique();
            entity.HasIndex(e => e.WeightSheetId, "UQ_WeightSheets_WeightSheetId").IsUnique();
            entity.Property(e => e.As400Id).ValueGeneratedOnAddOrUpdate();

            entity.Property(e => e.CreatedAt)
                .HasDefaultValueSql("(sysutcdatetime())")
                .HasAnnotation("Relational:DefaultConstraintName", "DF_purchase_WeightSheets_CreatedAt");
            entity.Property(e => e.CreationDate)
                .HasDefaultValueSql("(CONVERT([date],getdate()))")
                .HasAnnotation("Relational:DefaultConstraintName", "DF_WeightSheets_CreationDate");
            entity.Property(e => e.CustomRateDescription).HasMaxLength(255);
            entity.Property(e => e.Miles).HasColumnType("decimal(5, 2)");
            entity.Property(e => e.Notes).HasMaxLength(1000);
            entity.Property(e => e.Rate).HasColumnType("money");
            entity.Property(e => e.RateType)
                .HasMaxLength(1)
                .IsUnicode(false)
                .IsFixedLength();
            entity.Property(e => e.RowUid)
                .HasDefaultValueSql("(newid())")
                .HasAnnotation("Relational:DefaultConstraintName", "DF__WeightShe__RowUi__544C7222");
            entity.Property(e => e.ServerId)
                .HasDefaultValueSql("([system].[serverid]())")
                .HasAnnotation("Relational:DefaultConstraintName", "DF_WeightSheets_ServerId");
            entity.Property(e => e.UpdatedAt).HasPrecision(0);
            entity.Property(e => e.WeightSheetType)
                .IsRequired()
                .HasMaxLength(20);
            entity.Property(e => e.WeightmasterName).HasMaxLength(200);

            // Lifecycle status. 0 = Open is the database default, enforced by
            // DF_WeightSheets_StatusId (see SQL/AddWeightSheetStatus.sql).
            entity.Property(e => e.StatusId)
                .HasDefaultValue((byte)0)
                .HasAnnotation("Relational:DefaultConstraintName", "DF_WeightSheets_StatusId");

            entity.HasOne(d => d.Hauler).WithMany()
                .HasForeignKey(d => d.HaulerId)
                .HasConstraintName("FK_WeightSheets_Haulers");

            entity.HasOne(d => d.Location).WithMany()
                .HasForeignKey(d => d.LocationId)
                .OnDelete(DeleteBehavior.ClientSetNull)
                .HasConstraintName("FK_WeightSheets_Location");

            entity.HasOne(d => d.Status).WithMany(p => p.WeightSheets)
                .HasForeignKey(d => d.StatusId)
                .OnDelete(DeleteBehavior.Restrict)
                .HasConstraintName("FK_WeightSheets_WeightSheetStatuses");

            // Additional FKs the schema now enforces (FK_WeightSheets_Lots,
            // FK_WeightSheets_Servers). We configure these without navigations
            // on the principal side (Lots / Servers already participate in many
            // other relationships), so the mapping is one-directional from
            // WeightSheet outward.
            entity.HasOne<Lot>()
                .WithMany()
                .HasForeignKey(d => d.LotId)
                .OnDelete(DeleteBehavior.Restrict)
                .HasConstraintName("FK_WeightSheets_Lots");

            entity.HasOne<Server>()
                .WithMany()
